import json
from pathlib import Path


def write_chatml_jsonl(examples: list[dict], output_path: str):
    """
    Each example: {"system": str, "user": str, "assistant": str}
    Writes ChatML-formatted JSONL for TRL SFTTrainer.
    """
    lines = []
    for ex in examples:
        record = {
            "messages": [
                {"role": "system",    "content": ex.get("system", "")},
                {"role": "user",      "content": ex["user"]},
                {"role": "assistant", "content": ex["assistant"]},
            ]
        }
        lines.append(json.dumps(record))
    Path(output_path).write_text("\n".join(lines))
    print(f"Wrote {len(lines)} examples to {output_path}")


# Multi-turn conversation example
multi_turn_example = {
    "messages": [
        {"role": "system",    "content": "You are a helpful coding assistant."},
        {"role": "user",      "content": "How do I read a CSV in Python?"},
        {"role": "assistant", "content": "Use pandas: `df = pd.read_csv('file.csv')`"},
        {"role": "user",      "content": "How do I filter rows where age > 30?"},
        {"role": "assistant", "content": "`df[df['age'] > 30]`"},
    ]
}
# TRL will compute loss only on the assistant turns
